const discordData = $('When Executed by Another Workflow').item.json;

// 1. Get Monthly Income from Discord Input
const monthlyIncome = parseFloat(
  discordData.body.data.options.find(o => o.name === 'amount_in_php')?.value  
);

// 2. SSS 2025/2026 Rules
// Rate is 15%. Max MSC is now ₱35,000. Min MSC is ₱5,000.
const msc = Math.min(Math.max(monthlyIncome, 5000), 35000);
const sss = Math.round(msc * 0.15); 
// Note: This ₱5,250 max includes the mandatory WISP (Pension Booster) for income >₱20k.

// 3. PhilHealth 2025/2026 Rules
// Rate is 5%. Floor is ₱10,000. Ceiling is ₱100,000.
const philhealth = Math.min(Math.max(monthlyIncome * 0.05, 500), 5000);

// 4. Pag-IBIG
const pagibig = 200; // Standard contribution for income >₱5,000

// 5. BIR Tax Logic (TRAIN Law Graduated vs 8% Flat)
const annualIncome = monthlyIncome * 12;

// 8% Flat Rate Calculation (₱250k deduction for self-employed/professionals)
const taxableAnnual8 = Math.max(annualIncome - 250000, 0);
const monthlyTax8pct = (taxableAnnual8 * 0.08) / 12;

// Graduated Rate Calculation (2023-2026 Table)
function graduatedTax(annual) {
  if (annual <= 250000) return 0;
  if (annual <= 400000) return (annual - 250000) * 0.15;
  if (annual <= 800000) return 22500 + (annual - 400000) * 0.20;
  if (annual <= 2000000) return 102500 + (annual - 800000) * 0.25;
  if (annual <= 8000000) return 402500 + (annual - 2000000) * 0.30;
  return 2202500 + (annual - 8000000) * 0.35;
}
const monthlyTaxGrad = graduatedTax(annualIncome) / 12;

// 6. Final Take-Home
const takeHome8 = monthlyIncome - (sss + philhealth + pagibig + monthlyTax8pct);
const takeHomeGrad = monthlyIncome - (sss + philhealth + pagibig + monthlyTaxGrad);

// 7. Formatter and Message Building
const fmt = (n) => '₱' + Math.round(n).toLocaleString('en-PH');

return [{
  json: {
    message: [
      `👽 I have computed your government obligations, **${discordData.body.member.user.global_name}**! My alien tax algorithms are flawless.`,
      ``,
      `💰 **Monthly Income:** ${fmt(monthlyIncome)}`,
      ``,
      `**📋 Monthly Government Contributions:**`,
      `> 🔵 SSS: ${fmt(sss)} (at 15% rate)`,
      `> 🟢 PhilHealth: ${fmt(philhealth)} (at 5% rate)`,
      `> 🟡 Pag-IBIG: ${fmt(pagibig)}`,
      ``,
      `**🧾 BIR Income Tax (monthly set-aside):**`,
      `> 8% Flat Rate: **${fmt(monthlyTax8pct)}** ← *simpler, recommended*`,
      `> Graduated Rate: ${fmt(monthlyTaxGrad)}`,
      ``,
      `**🏠 Estimated Take-Home:**`,
      `> If 8% flat: **${fmt(takeHome8)}**`,
      `> If graduated: **${fmt(takeHomeGrad)}**`,
      ``,
      `⚠️ *Tax is paid quarterly to BIR. SSS max MSC is now ₱35,000 for 2025-2026. Set aside these amounts monthly to stay ready.*`
    ].join('\n'),
    token: discordData.body.token,
    application_id: discordData.body.application_id
  }
}];

